package com.cognizant.inventory.controller;import com.cognizant.inventory.model.Inventory;import com.cognizant.inventory.repository.InventoryRepository;import org.springframework.web.bind.annotation.*;import java.util.List;@RestController @RequestMapping("/inventory") public class InventoryController{private final InventoryRepository repo;public InventoryController(InventoryRepository repo){this.repo=repo;}@GetMapping public List<Inventory> all(){return repo.findAll();}@GetMapping("/{id}") public Inventory one(@PathVariable Long id){return repo.findById(id).orElseThrow();}@PostMapping public Inventory create(@RequestBody Inventory x){return repo.save(x);}}